void    vd_g_MemcpyU1_dw(U1 * u1_ap_cpydst, const U1 * u1_ap_CPYSRC, const U4 u4_a_NUM_BYTE);   /* Use G3M/double-word instruction  */

/*--------------------------------------------------------------------------------------------------------------*/
/* Note:                                                                                                        */
/*                                                                                                              */
/* vd_g_MemcpyU1_dw:                                                                                            */
/*  - Use the G3M/DW instruction to copy in double-word (8-byte) units whenever possible.                       */
/*  - The fastest way to do this is when the source and destination addresses can be aligned in 4-byte units.   */
/*    (8-byte alignment is the fastest, but the difference with 4-byte is small)                                */
/*    this means that the execution time depends on the address alignment, so be careful.                       */
/*  - If copy size is 16 bytes or larger, it is always faster than vd_g_MemcpyU1.                               */
/*    (Even if the alignment is not aligned)                                                                    */
/*--------------------------------------------------------------------------------------------------------------*/

